package com.hospital.management.controller.schedule;import com.hospital.management.service.*;import com.hospital.management.service.impl.DoctorScheduleServiceImpl;import com.hospital.management.util.RequestUtil;import javax.servlet.annotation.WebServlet;import javax.servlet.http.*;import java.io.IOException;
@WebServlet("/schedules/status")public class DoctorScheduleStatusServlet extends HttpServlet{private final DoctorScheduleService service;public DoctorScheduleStatusServlet(){this(new DoctorScheduleServiceImpl());}public DoctorScheduleStatusServlet(DoctorScheduleService s){service=s;}protected void doGet(HttpServletRequest q,HttpServletResponse r)throws IOException{r.sendError(405,"Schedule status changes require POST");}protected void doPost(HttpServletRequest q,HttpServletResponse r)throws IOException{Long id=ScheduleRequest.id(q.getParameter("scheduleId"));String a=q.getParameter("action");if(id==null||!("activate".equals(a)||"deactivate".equals(a))){r.sendError(400);return;}ServiceResult<Void>x="activate".equals(a)?service.activateSchedule(id,RequestUtil.buildAuditContext(q),ScheduleRequest.user(q)):service.deactivateSchedule(id,RequestUtil.buildAuditContext(q),ScheduleRequest.user(q));if(x.getStatus()==ServiceResult.Status.FORBIDDEN){r.sendError(403);return;}r.sendRedirect(q.getContextPath()+"/schedules?"+(x.isSuccess()?"message="+a+"d":"error="+(x.getStatus()==ServiceResult.Status.CONFLICT?"conflict":"error")));}}
